package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.body.ClassOrInterfaceDeclaration;
import com.github.javaparser.ast.body.FieldDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.body.Parameter;
import com.github.javaparser.ast.expr.AnnotationExpr;
import com.github.javaparser.ast.expr.AssignExpr;
import com.github.javaparser.ast.expr.FieldAccessExpr;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.expr.NameExpr;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.SimpleName;
import com.github.javaparser.ast.expr.StringLiteralExpr;
import com.github.javaparser.ast.expr.SuperExpr;
import com.github.javaparser.ast.expr.ThisExpr;
import com.github.javaparser.ast.expr.VariableDeclarationExpr;
import com.github.javaparser.ast.modifier.Modifier;
import com.github.javaparser.ast.stmt.BlockStmt;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.stmt.ReturnStmt;
import com.github.javaparser.ast.stmt.Statement;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.utils.SourceRoot;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

public class Main {

    private static final Set<String> LOMBOK_ANNOTATIONS = new HashSet<>(Arrays.asList(
        "EqualsAndHashCode",
        "ToString",
        "RequiredArgsConstructor",
        "AllArgsConstructor",
        "NoArgsConstructor",
        "Data",
        "Value",
        "Builder",
        "Getter",
        "Setter",
        "SneakyThrows",
        "NonNull",
        "Cleanup"
    ));

    public static void main(String[] args) throws IOException {
        if (args.length < 2) {
            System.out.println("Usage: java github.chains.Main <sourceDir> <outputDir>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);
        Path outputDir = Paths.get(args[1]);

        if (!Files.exists(sourceDir)) {
            System.err.println("Source directory does not exist: " + sourceDir);
            System.exit(1);
        }

        Files.createDirectories(outputDir);

        SourceRoot sourceRoot = new SourceRoot(sourceDir);
        List<CompilationUnit> compilationUnits = sourceRoot.tryToParseAll();

        int transformedCount = 0;
        for (CompilationUnit cu : compilationUnits) {
            if (cu.getResult().isPresent()) {
                CompilationUnit parsed = cu.getResult().get();
                if (hasLombokAnnotations(parsed)) {
                    transformCompilationUnit(parsed);

                    Path relativePath = sourceDir.relativize(Paths.get(cu.getStorage().get().getPath()));
                    Path outputPath = outputDir.resolve(relativePath);
                    Files.createDirectories(outputPath.getParent());
                    Files.writeString(outputPath, parsed.toString());
                    transformedCount++;
                    System.out.println("Transformed: " + relativePath);
                }
            }
        }

        System.out.println("Total files transformed: " + transformedCount);
    }

    private static boolean hasLombokAnnotations(CompilationUnit cu) {
        return cu.findAll(AnnotationExpr.class).stream()
            .anyMatch(annotation -> LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));
    }

    private static void transformCompilationUnit(CompilationUnit cu) {
        cu.getImports().removeIf(importDecl -> 
            importDecl.getNameAsString().startsWith("lombok."));

        cu.findAll(ClassOrInterfaceDeclaration.class).forEach(cls -> {
            removeLombokAnnotations(cls);

            List<FieldDeclaration> fields = cls.getFields();
            List<FieldDeclaration> finalFields = fields.stream()
                .filter(f -> f.getModifiers().stream()
                    .anyMatch(m -> m.getKeyword() == Modifier.Keyword.FINAL))
                .collect(Collectors.toList());

            generateRequiredArgsConstructor(cls, finalFields);
            generateToString(cls, fields);
            generateEqualsAndHashCode(cls, fields);
        });
    }

    private static void removeLombokAnnotations(ClassOrInterfaceDeclaration cls) {
        cls.getAnnotations().removeIf(annotation -> 
            LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));

        cls.findAll(FieldDeclaration.class).forEach(field -> {
            field.getAnnotations().removeIf(annotation -> 
                LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));
        });

        cls.findAll(MethodDeclaration.class).forEach(method -> {
            method.getAnnotations().removeIf(annotation -> 
                LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));
        });
    }

    private static void generateRequiredArgsConstructor(ClassOrInterfaceDeclaration cls, 
                                                        List<FieldDeclaration> finalFields) {
        if (finalFields.isEmpty()) {
            return;
        }

        MethodDeclaration constructor = cls.addConstructor(Modifier.Keyword.PRIVATE);
        constructor.setName(cls.getName());

        for (FieldDeclaration field : finalFields) {
            field.getVariable(0).ifPresent(var -> {
                Parameter param = constructor.addParameter(
                    var.getType().asString(), 
                    var.getNameAsString()
                );
                param.addModifier(Modifier.Keyword.FINAL);
            });
        }

        BlockStmt body = new BlockStmt();
        for (FieldDeclaration field : finalFields) {
            field.getVariable(0).ifPresent(var -> {
                AssignExpr assignExpr = new AssignExpr(
                    new FieldAccessExpr(new ThisExpr(), var.getNameAsString()),
                    new NameExpr(var.getNameAsString()),
                    AssignExpr.Operator.ASSIGN
                );
                body.addStatement(new ExpressionStmt(assignExpr));
            });
        }
        constructor.setBody(body);
    }

    private static void generateToString(ClassOrInterfaceDeclaration cls, 
                                         List<FieldDeclaration> fields) {
        if (fields.isEmpty()) {
            return;
        }

        MethodDeclaration toStringMethod = cls.addMethod("toString", Modifier.Keyword.PUBLIC);
        toStringMethod.addAnnotation("Override");
        toStringMethod.setType(String.class.getSimpleName());

        BlockStmt body = new BlockStmt();

        List<String> fieldNames = fields.stream()
            .flatMap(f -> f.getVariables().stream())
            .map(v -> v.getNameAsString())
            .collect(Collectors.toList());

        if (fieldNames.isEmpty()) {
            body.addStatement(new ReturnStmt(new StringLiteralExpr(cls.getNameAsString() + "()")));
        } else {
            StringBuilder sb = new StringBuilder();
            sb.append(cls.getNameAsString()).append("(");

            List<ExpressionStmt> statements = new ArrayList<>();
            StringBuilder exprBuilder = new StringBuilder();
            exprBuilder.append("new StringBuilder().append(\"").append(cls.getNameAsString()).append("(");

            for (int i = 0; i < fieldNames.size(); i++) {
                String fieldName = fieldNames.get(i);
                if (i > 0) {
                    exprBuilder.append("\").append(\", \").append(");
                } else {
                    exprBuilder.append("\").append(");
                }
                exprBuilder.append(fieldName).append(")");
            }
            exprBuilder.append(".append(\")\").toString()");

            body.addStatement(new ReturnStmt(new NameExpr(exprBuilder.toString())));
        }

        toStringMethod.setBody(body);
    }

    private static void generateEqualsAndHashCode(ClassOrInterfaceDeclaration cls, 
                                                   List<FieldDeclaration> fields) {
        if (fields.isEmpty()) {
            return;
        }

        MethodDeclaration equalsMethod = cls.addMethod("equals", Modifier.Keyword.PUBLIC);
        equalsMethod.addAnnotation("Override");
        equalsMethod.setType(boolean.class.getSimpleName());
        Parameter objParam = equalsMethod.addParameter(Object.class.getSimpleName(), "obj");
        objParam.addModifier(Modifier.Keyword.FINAL);

        BlockStmt equalsBody = new BlockStmt();
        equalsBody.addStatement(new ExpressionStmt(
            new AssignExpr(
                new VariableDeclarationExpr(boolean.class.getSimpleName(), "result"),
                new NameExpr("this == obj"),
                AssignExpr.Operator.ASSIGN
            )
        ));
        equalsMethod.setBody(equalsBody);

        MethodDeclaration hashCodeMethod = cls.addMethod("hashCode", Modifier.Keyword.PUBLIC);
        hashCodeMethod.addAnnotation("Override");
        hashCodeMethod.setType(int.class.getSimpleName());

        BlockStmt hashCodeBody = new BlockStmt();
        hashCodeBody.addStatement(new ReturnStmt(new NameExpr("java.util.Objects.hash()")));
        hashCodeMethod.setBody(hashCodeBody);
    }
}

