import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Arrays;
import java.util.HashSet;
import java.util.List;
import java.util.Optional;
import java.util.Set;
import java.util.stream.Collectors;

public class Main {

    private static final Set<String> LOMBOK_ANNOTATIONS = new HashSet<>(Arrays.asList(
        "EqualsAndHashCode",
        "ToString",
        "RequiredArgsConstructor",
        "AllArgsConstructor",
        "NoArgsConstructor",
        "Data",
        "Value",
        "Builder",
        "Getter",
        "Setter",
        "SneakyThrows",
        "NonNull",
        "Cleanup"
    ));

    public static void main(String[] args) throws IOException {
        if (args.length < 2) {
            System.out.println("Usage: java github.chains.Main <sourceDir> <outputDir>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);
        Path outputDir = Paths.get(args[1]);

        if (!Files.exists(sourceDir)) {
            System.err.println("Source directory does not exist: " + sourceDir);
            System.exit(1);
        }

        Files.createDirectories(outputDir);

        SourceRoot sourceRoot = new SourceRoot(sourceDir);
        List<ParseResult> compilationUnits = sourceRoot.tryToParseAll();

        int transformedCount = 0;
        for (ParseResult result : compilationUnits) {
            if (result.isSuccessful() && result.getResult().isPresent()) {
                CompilationUnit parsed = result.getResult().get();
                if (hasLombokAnnotations(parsed)) {
                    transformCompilationUnit(parsed);

                    Path relativePath = sourceDir.relativize(Paths.get(parsed.getStorage().get().getPath().toString()));
                    Path outputPath = outputDir.resolve(relativePath);
                    Files.createDirectories(outputPath.getParent());
                    Files.writeString(outputPath, parsed.toString());
                    transformedCount++;
                    System.out.println("Transformed: " + relativePath);
                }
            }
        }

        System.out.println("Total files transformed: " + transformedCount);
    }

    private static boolean hasLombokAnnotations(CompilationUnit cu) {
        return cu.findAll(AnnotationExpr.class).stream()
            .anyMatch(annotation -> LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));
    }

    private static void transformCompilationUnit(CompilationUnit cu) {
        cu.getImports().removeIf(importDecl -> 
            importDecl.getNameAsString().startsWith("lombok."));

        cu.findAll(ClassOrInterfaceDeclaration.class).forEach(cls -> {
            removeLombokAnnotations(cls);

