        cls.getAnnotations().removeIf(annotation -> 
            LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));

        cls.findAll(FieldDeclaration.class).forEach(field -> {
            field.getAnnotations().removeIf(annotation -> 
                LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));
        });

        cls.findAll(MethodDeclaration.class).forEach(method -> {
            method.getAnnotations().removeIf(annotation -> 
                LOMBOK_ANNOTATIONS.contains(annotation.getNameAsString()));
        });
    }

