        constructor.setPrivate(true);

        for (FieldDeclaration field : finalFields) {
            for (VariableDeclarator var : field.getVariables()) {
                constructor.addParameter(var.getType().clone(), var.getNameAsString())
                    .setFinal(true);
            }
        }

        BlockStmt body = new BlockStmt();
        for (FieldDeclaration field : finalFields) {
            for (VariableDeclarator var : field.getVariables()) {
                AssignExpr assignExpr = new AssignExpr(
                    new FieldAccessExpr(new ThisExpr(), var.getNameAsString()),
                    new NameExpr(var.getNameAsString()),
                    AssignExpr.Operator.ASSIGN
                );
                body.addStatement(new ExpressionStmt(assignExpr));
            }
        }
        constructor.setBody(body);
    }

    private static void generateToString(ClassOrInterfaceDeclaration cls, 
                                         List<FieldDeclaration> fields) {
        if (fields.isEmpty()) {
            return;
        }

        MethodDeclaration toStringMethod = cls.addMethod("toString");
        toStringMethod.setPublic(true);
        toStringMethod.addAnnotation("Override");
        toStringMethod.setType("String");

        BlockStmt body = new BlockStmt();

        List<String> fieldNames = fields.stream()
            .flatMap(f -> f.getVariables().stream())
            .map(VariableDeclarator::getNameAsString)
            .collect(Collectors.toList());

        if (fieldNames.isEmpty()) {
            body.addStatement(new ReturnStmt(new StringLiteralExpr(cls.getNameAsString() + "()")));
        } else {
            StringBuilder exprBuilder = new StringBuilder();
            exprBuilder.append("new StringBuilder().append(\"").append(cls.getNameAsString()).append("(");

            for (int i = 0; i < fieldNames.size(); i++) {
                String fieldName = fieldNames.get(i);
                if (i > 0) {
                    exprBuilder.append("\").append(\", \").append(");
                } else {
