        hashCodeMethod.setPublic(true);
        hashCodeMethod.addAnnotation("Override");
        hashCodeMethod.setType(PrimitiveType.INT);

        BlockStmt hashCodeBody = new BlockStmt();
        hashCodeBody.addStatement(new ReturnStmt(new NameExpr("0")));
        hashCodeMethod.setBody(hashCodeBody);
    }
